+var PyLong_Type: cpython.PyTypeObject = undefined;
+var PyFloat_Type: cpython.PyTypeObject = undefined;
+var PyUnicode_Type: cpython.PyTypeObject = undefined;
+var PyTuple_Type: cpython.PyTypeObject = undefined;
+
+var types_initialized = false;
+
+fn initTypes() void {
+    if (types_initialized) return;
+
+    // Minimal type object initialization
+    PyLong_Type = .{
+        .ob_base = .{ .ob_base = .{ .ob_refcnt = 1, .ob_type = undefined }, .ob_size = 0 },
+        .tp_name = "int",
+        .tp_basicsize = @sizeOf(PyLongObject),
+        .tp_itemsize = 0,
+        .tp_dealloc = null,
+        .tp_repr = null,
+        .tp_hash = null,
+        .tp_call = null,
+        .tp_str = null,
+        .tp_getattro = null,
+        .tp_setattro = null,
+        .tp_as_number = null,
+        .tp_as_sequence = null,
+        .tp_as_buffer = null,
+    };
+
+    PyFloat_Type = .{
+        .ob_base = .{ .ob_base = .{ .ob_refcnt = 1, .ob_type = undefined }, .ob_size = 0 },
+        .tp_name = "float",
+        .tp_basicsize = @sizeOf(PyFloatObject),
+        .tp_itemsize = 0,
+        .tp_dealloc = null,
+        .tp_repr = null,
+        .tp_hash = null,
+        .tp_call = null,
+        .tp_str = null,
+        .tp_getattro = null,
