+        .ob_base = .{ .ob_base = .{ .ob_refcnt = 1, .ob_type = undefined }, .ob_size = 0 },
+        .tp_name = "str",
+        .tp_basicsize = @sizeOf(PyUnicodeObject),
+        .tp_itemsize = 1,
+        .tp_dealloc = null,
+        .tp_repr = null,
